output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?award ?awardLabel WHERE {
  wd:Q184342 p:P166 ?awardStatement .
  ?awardStatement ps:P166 ?award .
  OPTIONAL {
    ?award rdfs:label ?awardLabel .
  }
  FILTER(CONTAINS(STR(?awardLabel) , "Kids' Choice Award"))
  FILTER(lang(?awardLabel) = 'en')
}

args.sparql:
PREFIX math: <http://www.w3.org/2005/xpath-functions/math#>
SELECT ?award ?awardLabel
WHERE {
  wd:Q184342 p:P166 ?awardStatement.
  ?awardStatement ps:P166 ?award.
  ?awardStatement pq:P585 ?date.
  FILTER (math:year(?date) = 2008)
  OPTIONAL { ?award rdfs:label ?awardLabel. }
}

